      MIS_REG_OFFSET:     rdata = {30'b0, MIS_WIRE};
      RIS_REG_OFFSET:     rdata = {30'b0, RIS_WIRE};
      default:            rdata = 32'hDEADBEEF;
    endcase
  end

  assign dat_o = rdata;

  reg ack_reg;
  always @(posedge clk_i or posedge rst_i) begin
    if (rst_i)
      ack_reg <= 1'b0;
    else
      ack_reg <= wb_valid & ~ack_reg;
  end

  assign ack_o = ack_reg;

  // ============================================================================
  // SHA256 Core
  // ============================================================================
  sha256_core sha256_core_inst (
      .clk(clk),
      .reset_n(reset_n),
      .init(init),
      .next(next),
      .mode(mode),
      .block(block),
      .ready(ready),
      .digest(digest),
      .digest_valid(digest_valid)
  );

endmodule
